function Topbar({ title, setPage, darkMode, toggleTheme }) {
  return (
    <div className="topbar">
      <div className="topbar-title">{title}</div>
      <div className="topbar-actions">
        <button
          className={`theme-toggle-btn ${darkMode ? "dark" : "light"}`}
          onClick={toggleTheme}
          title={darkMode ? "Mudar para claro" : "Mudar para escuro"}
        >
          <span className="toggle-track">
            <span className="toggle-thumb" />
          </span>
          <span className="toggle-icon">{darkMode ? "🌙" : "☀️"}</span>
        </button>
        <button className="btn btn-primary btn-sm" onClick={() => setPage("nova-tarefa")}>
          + Nova Tarefa
        </button>
      </div>
    </div>
  );
}

export default Topbar;
